example.code:
{
  "program_id": "acme-hardware-launch",
  "workstreams": [
    {
      "id": "ws-1",
      "name": "hardware",
      "mode": "predictive",
      "cadence": "monthly milestone",
      "lead": "U_HW_LEAD",
      "rationale": "Regulated hardware path with FDA submission gate; predictive plan required."
    },
    {
      "id": "ws-2",
      "name": "firmware",
      "mode": "agile",
      "cadence": "2-week sprints",
      "lead": "U_FW_LEAD",
      "rationale": "Firmware features iterate weekly with hardware prototypes; agile fits feedback loop."
    }
  ],
  "handoffs": [
    {
      "from_ws": "ws-1",
      "to_ws": "ws-2",
      "inputs": [
        "board rev"
      ],
      "outputs": [
        "working prototype"
      ],
      "acceptance_criteria": [
        "passes smoke test"
      ],
      "sla_days": 5,
      "escalation_owner": "U_PROGRAM_DIRECTOR"
    }
  ],
  "governance": {
    "layer": "single",
    "decision_authority": "U_STEERING_COMMITTEE"
  },
  "reporting_dashboard": {
    "common_metrics": [
      "cost variance",
      "schedule variance",
      "open risks"
    ],
    "translation_rules": [
      "velocity * avg-story-cost = cost variance equivalent"
    ]
  }
}
